  ('locality-6f0ba476-moex-00025', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲依法受監護宣告。甲受宣告前，並未與他人訂立意定監護契約。法院選定乙任甲之監護人。依 民法關於監護宣告之規定，下列敘述何者正確？', '["乙得以甲之財產購買金融債券、金融機構承兌匯票或保證商業本票", "乙得請求報酬，其數額由甲之親屬會議，按甲之資力酌定之", "乙代理甲購置或處分動產時，非經法院許可，不生效力", "甲之財產，由乙管理。執行監護職務之必要費用，由乙負擔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00026', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲男之父為乙。乙之父親為丙。丙之母為丁。丁之妹為戊，戊有一子庚。依民法關於禁止收養親 屬之規定，下列敘述何者錯誤？', '["設戊欲收養丙，戊與丙屬禁止收養親屬", "設庚欲收養乙，庚與乙非屬禁止收養親屬", "設庚欲收養甲，庚與甲屬禁止收養親屬", "設丙欲收養庚，丙與庚屬禁止收養親屬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00027', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '依民法規定，下列關於結婚形式要件之敘述，何者正確？', '["應有公開儀式", "結婚之書面，應當事人親自書寫", "結婚之書面，應經公證", "應由雙方當事人向戶政機關為結婚之登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00028', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲乙為配偶，採分別財產制。乙死亡時，乙與甲之子女丙已死亡。乙尚有外祖父丁、外祖母戊在 世，乙生前均繼續扶養。乙另有祖母庚，與再婚對象辛共同生活。就乙留下之遺產新臺幣（下同） 1,800萬元，戊應可繼承多少？', '["600萬元", "450萬元", "300萬元", "200萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00029', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於遺囑撤回之敘述，何者錯誤？', '["遺囑人於為遺囑後所為之行為，與遺囑有相牴觸者，其牴觸部分，遺囑視為撤回", "遺囑撤回之方式，為遺囑方式之任何一種均可，但必須與原遺囑同其方式", "撤回前遺囑，且同時另為其他內容之遺囑，亦無不可", "遺囑之撤回，不限於全部，即其一部分亦可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00030', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲、乙為夫妻，有丙、丁、戊三子。丙有一子己，丁有一子庚，戊有一子辛。丙先於甲死亡，甲 死亡時，丁依法拋棄繼承。甲之遺產，由何人繼承？', '["乙、戊", "乙、己、戊", "乙、己、庚、戊", "乙、己、庚、辛"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "7278b8eb62a0", "answer_pdf_sha1": "42e3c5c0be26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00031', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'essay', '請回答下列問題：
營利事業以往年度的虧損，若要從本年度純益額中扣除後，再行核課
本年度的營利事業所得稅，必須符合那些條件？（10分）
A公司 112年帳上淨利200萬元，投資國內其他營利事業獲配現金股
利 100萬元，出售 102年取得土地的利益450萬元，其餘收入及費用
均符合稅法規定按帳載申報，經國稅局按申報金額核准。113 年申報
之淨利為600萬元，這兩年均採會計師簽證申報，並如期申報，試問
A 公司 113 年可扣除 112 年度虧損為多少？申報之課稅所得為多少？
（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00032', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'essay', '請回答下列問題：
甲於 104 年 3 月 5 日以 1,300 萬元買進位於中華民國境內的房屋及其
座落基地並完成所有權移轉登記，其中 700萬元為房屋購入的價格，
600 萬元為土地購入的價格，當時的房屋評定價值為 450 萬元，公告
土地現值為 400萬元。甲於 111年 2 月 1 日將該房屋、土地贈與甲已
成年的兒子乙，贈與當時的房屋評定價值為 480萬元，公告土地現值
為 500萬元，類似物件的成交價格為 1,500 萬元。111 年度甲無其他贈
與。乙於 114 年 5 月 5 日以 1,700 萬元出售該房屋、土地並完成所有
權移轉登記，出售時乙採用公告土地現值780萬元申報土地的移轉現
值，乙未提示取得、改良及移轉的費用。假設乙出售房屋、土地年度
的消費者物價指數為他受贈年度的 110%，為甲購入房屋、土地年度的
120%。該房屋、土地不符合自住的條件。甲和乙皆為中華民國境內居
住之個人，也是經常居住中華民國境內之中華民國國民。
試問本例中的房屋、土地有贈與稅嗎？若有，誰要繳納贈與稅，必須
於何時辦理申報，以及稅額為多少？誰要繳納所得稅，必須於何時申
報繳納，以及稅額為多少？（15分）
若在第小題中甲於 111 年 2 月 1 日將他於 104 年 3 月 5 日購入的房
屋、土地贈與其配偶，並非贈與其子乙，但不幸甲於 112 年 12月 1 日
過世，甲另遺留有價值 8,000 萬元的遺產，除了甲的配偶和兒子乙以
外，甲無其他親屬。試問本例中在 111年度有贈與稅嗎？若有，誰要
繳納贈與稅，必須於何時辦理申報？本例中的房屋、土地在 111年度
有所得稅嗎？若有，誰要繳納所得稅，必須於何時申報繳納？本例中
有遺產稅嗎？若有，必須於何時辦理申報？（5分）
若在第小題中甲於 111 年 2 月 1 日將他於 104 年 3 月 5 日購入的房
屋、土地交付信託，以其子乙為受益人，信託期間為 10年，期滿由受
益人取得信託利益。試問本例中在 111年度有贈與稅嗎？若有，誰要
繳納贈與稅，必須於何時辦理申報，以及稅額為多少？本例中的房屋、
土地在 111年度有所得稅嗎？若有，誰要繳納所得稅，如何計算稅額，
必須於何時申報繳納？（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00033', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法第22條規定，關於核課期間之起算，下列敘述何者錯誤？', '["土地增值稅自稅捐稽徵機關收件日起算", "依法應由納稅義務人申報繳納之稅捐，已在規定期間內申報者，自申報日起算", "依法應由納稅義務人申報繳納之稅捐，未在規定期間內申報者，自規定申報期間屆滿之日起算", "由稅捐稽徵機關按稅籍底冊徵收之稅捐，自該稅捐所屬徵期屆滿之翌日起算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": "af317452f60b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00034', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法第41條規定，納稅義務人以詐術或其他不正當方法逃漏稅捐者，個人逃漏稅額在 多少元以上，營利事業逃漏稅額在多少元以上者，處一年以上七年以下有期徒刑，併科新臺幣 1,000萬元以上1億元以下罰金。', '["500萬；1,000萬", "500萬；5,000萬", "1,000萬；5,000萬", "1,000萬；1億"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": "af317452f60b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
